const err = $input.first().json;
const execution = err.execution || {};
const workflow = err.workflow || {};
return [{
  json: {
    loggedAt: new Date().toISOString(),
    workflowName: workflow.name || 'AI LinkedIn Poster',
    workflowId: workflow.id,
    executionId: execution.id,
    executionUrl: execution.url,
    lastNodeExecuted: execution.lastNodeExecuted,
    errorMessage: execution.error?.message || err.trigger?.error?.message || 'Unknown error',
    mode: execution.mode,
    hint: 'Check main workflow execution in n8n UI for full stack trace.'
  }
}];
